import socket
import json
import threading

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.host = host
        self.port = port
        self.players = []
        self.game_state = {'status': 'running', 'level': 1}
        self.lock = threading.Lock()
        self.server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server.bind((self.host, self.port))
        print(f"Server started at {self.host}:{self.port}")

    def handle_queries(self):
        while True:
            data, addr = self.server.recvfrom(1024)
            if data.decode() == 'STATUS':
                self.send_status(addr)

    def send_status(self, addr):
        with self.lock:
            response = {
                'players': self.players,
                'game_state': self.game_state
            }
            response_data = json.dumps(response).encode('utf-8')
            if len(response_data) > 65507:  # UDP max size
                response_data = response_data[:65507]
            self.server.sendto(response_data, addr)

    def add_player(self, player_name):
        with self.lock:
            self.players.append(player_name)

    def remove_player(self, player_name):
        with self.lock:
            self.players.remove(player_name)

    def start(self):
        threading.Thread(target=self.handle_queries, daemon=True).start()

if __name__ == "__main__":
    game_server = GameServer()
    game_server.start()
    # Example usage
    game_server.add_player('Player1')
    game_server.add_player('Player2')